mapper.select:
SELECT IFNULL(SUM(( SELECT COUNT(A.UIE_UIL_CODE) FROM TBL_INSTITUTION_LIBRARY_EBOOK A WHERE institution_library_master.UIL_CODE = A.UIE_UIL_CODE)), 0) AS count FROM TBL_INSTITUTION_LIBRARY_MASTER institution_library_master LEFT OUTER JOIN TBL_INSTITUTION_MASTER institution_master ON institution_library_master.UIL_UIS_CODE = institution_master.UIS_CODE LEFT OUTER JOIN TBL_INSTITUTION_LIBRARY_EXCLUDE exclude ON exclude.UILE_UIL_CODE = institution_library_master.UIL_CODE AND exclude.UILE_UIS_CODE = institution_master.UIS_CODE WHERE 1 = 1 AND institution_library_master.UIL_DISPLAY_STARTDATE <= CURRENT_TIMESTAMP AND institution_library_master.UIL_DISPLAY_ENDDATE >= CURRENT_TIMESTAMP AND institution_library_master.UIL_USEYN = 'Y'
AND institution_library_master.UIL_UIS_CODE = #{searchUisCode}
AND ( institution_library_master.UIL_UIS_CODE = ''
OR institution_library_master.UIL_UIS_CODE = #{searchUisCode}
)
AND NOT EXISTS ( SELECT 1 FROM TBL_INSTITUTION_LIBRARY_EXCLUDE sub_exclude WHERE sub_exclude.UILE_UIL_CODE = institution_library_master.UIL_CODE AND sub_exclude.UILE_UIS_CODE = #{searchUisCode} )

SELECT DISTINCT institution_library_master.UIL_CODE AS uil_code ,institution_library_master.UIL_NAME AS uil_name ,institution_master.UIS_USE_ADULT_BOOK AS uis_use_adult_book ,( SELECT COUNT(A.UIE_UIL_CODE) AS uie_uis_count FROM TBL_INSTITUTION_LIBRARY_EBOOK A WHERE institution_library_master.UIL_CODE = A.UIE_UIL_CODE ) AS book_count FROM TBL_INSTITUTION_LIBRARY_MASTER institution_library_master LEFT OUTER JOIN TBL_INSTITUTION_MASTER institution_master ON institution_library_master.UIL_UIS_CODE = institution_master.UIS_CODE LEFT OUTER JOIN TBL_INSTITUTION_LIBRARY_EXCLUDE exclude ON exclude.UILE_UIL_CODE = institution_library_master.UIL_CODE AND exclude.UILE_UIS_CODE = institution_master.UIS_CODE WHERE 1 = 1 AND institution_library_master.UIL_DISPLAY_STARTDATE <= CURRENT_TIMESTAMP AND institution_library_master.UIL_DISPLAY_ENDDATE >= CURRENT_TIMESTAMP AND institution_library_master.UIL_USEYN = 'Y'
AND institution_library_master.UIL_CODE NOT IN ('UIL0000000115')
AND institution_library_master.UIL_UIS_CODE = #{searchUisCode}
AND ( institution_library_master.UIL_UIS_CODE = ''
OR institution_library_master.UIL_UIS_CODE = #{searchUisCode}
)
AND NOT EXISTS ( SELECT 1 FROM TBL_INSTITUTION_LIBRARY_EXCLUDE sub_exclude WHERE sub_exclude.UILE_UIL_CODE = institution_library_master.UIL_CODE AND sub_exclude.UILE_UIS_CODE = #{searchUisCode} )
ORDER BY (Case When UIL_UIS_CODE Is Null Then 2 WHEN UIL_UIS_CODE = '' THEN 1 Else 0 End) ASC, institution_library_master.UIL_DISPLAY_NUMBER ASC

SELECT COUNT(institution_library_master.UIL_CODE) AS count FROM TBL_INSTITUTION_LIBRARY_MASTER institution_library_master LEFT OUTER JOIN TBL_INSTITUTION_MASTER institution_master ON institution_library_master.UIL_UIS_CODE = institution_master.UIS_CODE WHERE 1 = 1 AND institution_library_master.UIL_DISPLAY_STARTDATE <= CURRENT_TIMESTAMP AND institution_library_master.UIL_DISPLAY_ENDDATE >= CURRENT_TIMESTAMP AND institution_library_master.UIL_USEYN = 'Y'
AND institution_library_master.UIL_UIS_CODE = #{searchUisCode}
AND ( institution_library_master.UIL_UIS_CODE = #{searchUisCode} )

SELECT institution_library_master.UIL_CODE AS uil_code , institution_library_master.UIL_NAME AS uil_name , institution_master.UIS_USE_ADULT_BOOK AS uis_use_adult_book ,( SELECT COUNT(UIE_UIL_CODE) AS uie_uis_count FROM bookers.TBL_INSTITUTION_LIBRARY_EBOOK WHERE institution_library_master.UIL_CODE = UIE_UIL_CODE ) AS book_count FROM TBL_INSTITUTION_LIBRARY_MASTER institution_library_master LEFT OUTER JOIN TBL_INSTITUTION_MASTER institution_master ON institution_library_master.UIL_UIS_CODE = institution_master.UIS_CODE WHERE 1 = 1 AND institution_library_master.UIL_DISPLAY_STARTDATE <= CURRENT_TIMESTAMP AND institution_library_master.UIL_DISPLAY_ENDDATE >= CURRENT_TIMESTAMP AND institution_library_master.UIL_USEYN = 'Y'
AND institution_library_master.UIL_UIS_CODE = #{searchUisCode}
AND (
institution_library_master.UIL_UIS_CODE = #{searchUisCode}
)
ORDER BY (Case When UIL_UIS_CODE Is Null Then 2 WHEN UIL_UIS_CODE = '' THEN 1 Else 0 End) ASC, institution_library_master.UIL_DISPLAY_NUMBER ASC

SELECT contents_master.UCM_CODE AS ucm_code , contents_master.UCM_EBOOK_ISBN AS ucm_ebook_isbn , contents_master.UCM_FILE_TYPE AS ucm_file_type , contents_master.UCM_TITLE AS ucm_title , contents_master.UCM_SUB_TITLE AS ucm_sub_title , contents_master.UCM_UCP_CODE AS ucm_ucp_code , contents_master.UCM_WRITER AS ucm_writer , contents_master.UCM_THUMB_URL AS ucm_cover_url , cp_master.UCP_NAME AS ucp_name , cp_master.UCP_CP_BRAND AS ucp_cp_brand , contents_master.UCM_PUBLISHER AS ucm_publisher , contents_master.UCM_INTRO AS ucm_intro , IFNULL(library.UME_CODE, '') AS ume_code , contents_master.UCM_WEBDRM2_YN AS ucm_webdrm_yn , (SELECT COUNT(UME_CODE) FROM TBL_MEMBER_LIBRARY_BOOK WHERE UME_UCM_CODE = contents_master.UCM_CODE AND UME_READ_STATUS = 'R' AND UME_STATUS = 'A') AS ucm_read_count FROM TBL_CONTENTS_MASTER contents_master LEFT OUTER JOIN TBL_CP_MASTER cp_master ON contents_master.UCM_UCP_CODE = cp_master.UCP_CODE LEFT OUTER JOIN TBL_MEMBER_LIBRARY_BOOK library ON library.UME_UCM_CODE = contents_master.UCM_CODE AND library.UME_UM_CODE = #{um_code} AND library.UME_STATUS = 'A'
JOIN TBL_RETURN_CONTENTS return_contents ON contents_master.UCM_CODE = return_contents.URC_UCM_CODE
LEFT OUTER JOIN ( SELECT UCE_UCM_CODE FROM TBL_CONTENTS_EXCLUDE WHERE UCE_UIS_CODE = #{uis_code} ) V ON V.UCE_UCM_CODE = contents_master.UCM_CODE WHERE 1 = 1 AND V.uce_ucm_code is null AND contents_master.UCM_STATUS = 'S' AND contents_master.UCM_SVRYN = 'Y'
AND contents_master.UCM_UCT_CODE LIKE CONCAT(LEFT(#{uct_code}, 8), '%')
AND substring(contents_master.UCM_UCT_CODE, 4,1) = #{uct_type}
AND contents_master.UCM_CODE IN (SELECT UIE_UCM_CODE FROM TBL_INSTITUTION_LIBRARY_EBOOK WHERE UIE_UIL_CODE = #{uil_code})
AND return_contents.URC_UIS_CODE = #{uis_code}
AND contents_master.UCM_COPY_BOOK_FLAG = 'N'
LIMIT #{pagenum}, #{pageSize}

SELECT contents_master.UCM_CODE AS ucm_code , contents_master.UCM_TITLE AS ucm_title , contents_master.UCM_WRITER AS ucm_writer , contents_master.UCM_PUBLISHER AS ucp_brand , DATE_FORMAT(contents_master.UCM_EBOOK_PUBDATE, '%Y/%m/%d') AS ucm_ebook_pubdate , contents_master.UCM_THUMB_URL AS ucm_cover_url , contents_master.UCM_UCT_CODE AS ucm_uct_code , contents_master.UCM_FILE_TYPE AS ucm_file_type , contents_master.UCM_LIMIT_AGE AS ucm_limit_age , contents_master.UCM_UCS_CODE AS ucm_ucs_code , contents_master.UCM_SERIES_NO AS ucm_series_no , (SELECT COUNT(UCM_CODE) FROM TBL_CONTENTS_MASTER WHERE ucm_ucs_code != '' AND UCM_UCS_CODE = contents_master.UCM_UCS_CODE AND UCM_STATUS = 'S' AND UCM_SVRYN = 'Y' ) AS ucm_series_count FROM TBL_CONTENTS_MASTER contents_master
JOIN TBL_RETURN_CONTENTS return_contents ON contents_master.UCM_CODE = return_contents.URC_UCM_CODE
LEFT OUTER JOIN ( SELECT UCE_UCM_CODE FROM TBL_CONTENTS_EXCLUDE WHERE UCE_UIS_CODE = #{uis_code} ) V ON V.UCE_UCM_CODE = contents_master.UCM_CODE WHERE 1 = 1 AND contents_master.UCM_STATUS = 'S' AND contents_master.UCM_SVRYN = 'Y'
AND return_contents.URC_UIS_CODE = #{uis_code}
AND contents_master.UCM_COPY_BOOK_FLAG = 'N'
AND contents_master.UCM_UCS_CODE = #{ucm_ucs_code} AND contents_master.UCM_CODE != #{ucm_code}
AND contents_master.UCM_UCS_CODE is not null AND contents_master.UCM_CODE = #{ucm_code}
ORDER BY contents_master.UCM_SERIES_NO

mapper.update:
UPDATE 
	TBL_MEMBER_LIBRARY_BOOK
SET
	UME_STATUS = #{ume_status}
	, UME_MOD_DATE = CURRENT_TIMESTAMP

	, UME_INPUT_DATE = CURRENT_TIMESTAMP

WHERE
	UME_UML_CODE = #{uml_code}
AND
	UME_UCM_CODE = #{ume_ucm_code}

mapper.select:
SELECT COUNT(*) AS count FROM TBL_CONTENTS_MASTER contents_master LEFT OUTER JOIN TBL_CATEGORY_MASTER category_master ON contents_master.UCM_UCT_CODE = category_master.UCT_CODE
JOIN TBL_RETURN_CONTENTS return_contents ON contents_master.UCM_CODE = return_contents.URC_UCM_CODE
LEFT OUTER JOIN ( SELECT UCE_UCM_CODE FROM TBL_CONTENTS_EXCLUDE WHERE UCE_UIS_CODE = #{uis_code} ) V ON V.UCE_UCM_CODE = contents_master.UCM_CODE WHERE 1 = 1
AND contents_master.UCM_UCP_CODE = #{uis_ucp_code}
AND category_master.UCT_TYPE = #{uct_type}
AND contents_master.UCM_MAIN_CODE = LEFT(#{uct_code}, 8)
AND contents_master.UCM_UCT_CODE = #{uct_code}
AND contents_master.UCM_STATUS = 'S' AND contents_master.UCM_SVRYN = 'Y' AND V.uce_ucm_code is null
AND contents_master.UCM_COPY_BOOK_FLAG = 'N'
AND return_contents.URC_UIS_CODE = #{uis_code}
AND category_master.UCT_TYPE != 'C'

SELECT contents_master.UCM_CODE AS ucm_code , contents_master.UCM_EBOOK_ISBN AS ucm_ebook_isbn , contents_master.UCM_TITLE AS ucm_title , contents_master.UCM_SUB_TITLE AS ucm_sub_title , contents_master.UCM_WRITER AS ucm_writer , contents_master.UCM_PUBLISHER AS ucp_brand , DATE_FORMAT(contents_master.UCM_EBOOK_PUBDATE, '%Y-%m-%d') AS ucm_ebook_pubdate , contents_master.UCM_THUMB_URL AS ucm_cover_url , contents_master.UCM_UCT_CODE AS ucm_uct_code , contents_master.UCM_FILE_TYPE AS ucm_file_type , contents_master.UCM_LIMIT_AGE AS ucm_limit_age , contents_master.UCM_UCS_CODE AS ucm_ucs_code , contents_master.UCM_SERIES_NO AS ucm_series_no , contents_master.UCM_INTRO AS ucm_intro , IFNULL(library.UME_CODE, '') AS ume_code , contents_master.UCM_WEBDRM2_YN AS ucm_webdrm_yn , (SELECT COUNT(UME_CODE) FROM TBL_MEMBER_LIBRARY_BOOK WHERE UME_UCM_CODE = contents_master.UCM_CODE AND UME_READ_STATUS = 'R' AND UME_STATUS = 'A') AS ucm_read_count , ROUND(( (agg.read_cnt * 0.35) + ((agg.read_time / 3600) * 0.10) + (agg.read_percent * 0.20) + (agg.order_cnt * 0.35) ) / 100, 2) AS score
FROM ( SELECT tdpl.ucm_code, SUM(tdpl.read_cnt) AS read_cnt, SUM(tdpl.read_time) AS read_time, AVG(tdpl.read_percent) AS read_percent, SUM(tdpl.order_cnt) AS order_cnt FROM TBL_DAILY_POPULAR_LOG tdpl WHERE tdpl.LOG_YMD >= DATE_SUB(CURDATE(), INTERVAL 1 DAY) AND tdpl.LOG_YMD < CURDATE() GROUP BY tdpl.ucm_code ) agg JOIN TBL_CONTENTS_MASTER contents_master ON contents_master.ucm_code = agg.ucm_code LEFT OUTER JOIN TBL_CATEGORY_MASTER category_master ON contents_master.UCM_UCT_CODE = category_master.UCT_CODE LEFT OUTER JOIN TBL_MEMBER_LIBRARY_BOOK library ON library.UME_UCM_CODE = contents_master.UCM_CODE AND library.UME_UM_CODE = #{um_code} AND library.UME_STATUS = 'A'
JOIN TBL_RETURN_CONTENTS return_contents ON contents_master.UCM_CODE = return_contents.URC_UCM_CODE
LEFT OUTER JOIN ( SELECT UCE_UCM_CODE FROM TBL_CONTENTS_EXCLUDE WHERE UCE_UIS_CODE = #{uis_code} ) V ON V.UCE_UCM_CODE = contents_master.UCM_CODE
WHERE 1 = 1
AND contents_master.UCM_UCP_CODE = #{uis_ucp_code}
AND contents_master.UCM_STATUS = 'S' AND contents_master.UCM_SVRYN = 'Y' AND V.uce_ucm_code is null
AND return_contents.URC_UIS_CODE = #{uis_code}
AND contents_master.UCM_COPY_BOOK_FLAG = 'N'
ORDER BY score DESC LIMIT #{limit_count}

SELECT COUNT(contents_master.UCM_CODE) AS count FROM TBL_CONTENTS_MASTER contents_master LEFT OUTER JOIN TBL_CATEGORY_MASTER category_master ON contents_master.UCM_UCT_CODE = category_master.UCT_CODE LEFT OUTER JOIN TBL_CP_MASTER cp_master ON contents_master.UCM_UCP_CODE = cp_master.UCP_CODE
JOIN TBL_RETURN_CONTENTS return_contents ON contents_master.UCM_CODE = return_contents.URC_UCM_CODE
LEFT OUTER JOIN ( SELECT UCE_UCM_CODE FROM TBL_CONTENTS_EXCLUDE WHERE UCE_UIS_CODE = #{uis_code} ) V ON V.UCE_UCM_CODE = contents_master.UCM_CODE
WHERE 1 = 1
AND contents_master.UCM_UCP_CODE = #{uis_ucp_code}
AND category_master.UCT_TYPE = #{uct_type}
AND contents_master.UCM_MAIN_CODE = LEFT(#{uct_code}, 8)
AND contents_master.UCM_UCT_CODE = #{uct_code}
AND contents_master.UCM_STATUS = 'S' AND contents_master.UCM_SVRYN = 'Y' AND V.uce_ucm_code is null
AND return_contents.URC_UIS_CODE = #{uis_code}
AND contents_master.UCM_COPY_BOOK_FLAG = 'N'
AND category_master.UCT_TYPE != 'C'

SELECT contents_master.UCM_CODE AS ucm_code , contents_master.UCM_EBOOK_ISBN AS ucm_ebook_isbn , contents_master.UCM_TITLE AS ucm_title , contents_master.UCM_SUB_TITLE AS ucm_sub_title , contents_master.UCM_WRITER AS ucm_writer , contents_master.UCM_PUBLISHER AS ucp_brand , DATE_FORMAT(contents_master.UCM_EBOOK_PUBDATE, '%Y.%m.%d') AS ucm_ebook_pubdate , contents_master.UCM_THUMB_URL AS ucm_cover_url , contents_master.UCM_UCT_CODE AS ucm_uct_code , contents_master.UCM_FILE_TYPE AS ucm_file_type , contents_master.UCM_LIMIT_AGE AS ucm_limit_age , contents_master.UCM_UCS_CODE AS ucm_ucs_code , contents_master.UCM_SERIES_NO AS ucm_series_no , contents_master.UCM_SERIES_NO AS ucm_series_no , (SELECT COUNT(UCM_CODE) FROM TBL_CONTENTS_MASTER WHERE ucm_ucs_code != '' AND UCM_UCS_CODE = contents_master.UCM_UCS_CODE AND UCM_STATUS = 'S' AND UCM_SVRYN = 'Y' ) AS ucm_series_count FROM TBL_MEMBER_LIBRARY_BOOK member_library_book LEFT OUTER JOIN TBL_MEMBER_LIBRARY member_library ON member_library.UML_CODE = member_library_book.UME_UML_CODE LEFT OUTER JOIN TBL_CONTENTS_MASTER contents_master ON member_library_book.UME_UCM_CODE = contents_master.UCM_CODE
JOIN TBL_RETURN_CONTENTS return_contents ON contents_master.UCM_CODE = return_contents.URC_UCM_CODE AND return_contents.URC_UCM_CODE = member_library_book.UME_UCM_CODE
LEFT OUTER JOIN ( SELECT UCE_UCM_CODE FROM TBL_CONTENTS_EXCLUDE WHERE UCE_UIS_CODE = #{uis_code} ) V ON V.UCE_UCM_CODE = contents_master.UCM_CODE WHERE member_library.UML_TYPE = 'D' AND member_library_book.UME_STATUS = 'A' AND contents_master.UCM_SVRYN = 'Y' AND contents_master.UCM_STATUS = 'S' AND V.uce_ucm_code is null
AND return_contents.URC_UIS_CODE = #{uis_code}
AND contents_master.UCM_COPY_BOOK_FLAG = 'N'
AND contents_master.UCM_UCP_CODE = #{uis_ucp_code}
AND contents_master.UCM_UCP_CODE NOT IN ('UCP0000000425','UCP0000000013')
AND ( REPLACE(contents_master.UCM_TITLE,' ','') COLLATE utf8_general_ci LIKE CONCAT('%', #{searchName}, '%') OR REPLACE(contents_master.UCM_WRITER,' ','') COLLATE utf8_general_ci LIKE CONCAT('%', #{searchName}, '%') OR REPLACE(contents_master.UCM_PUBLISHER,' ','') COLLATE utf8_general_ci LIKE CONCAT('%', #{searchName}, '%') ) group by member_library_book.UME_UCM_CODE LIMIT #{pagenum}, #{pageSize}

SELECT count(book_report.UBR_CODE) AS book_report_count , book_report.UBR_CODE AS ubr_code , book_report.UBR_TITLE AS ubr_title , contents_master.UCM_CODE AS ucm_code , contents_master.UCM_EBOOK_ISBN AS ucm_ebook_isbn , contents_master.UCM_TITLE AS ucm_title , contents_master.UCM_SUB_TITLE AS ucm_sub_title , contents_master.UCM_WRITER AS ucm_writer , contents_master.UCM_PUBLISHER AS ucp_brand , DATE_FORMAT(contents_master.UCM_EBOOK_PUBDATE, '%Y.%m.%d') AS ucm_ebook_pubdate , contents_master.UCM_THUMB_URL AS ucm_cover_url , contents_master.UCM_UCT_CODE AS ucm_uct_code , contents_master.UCM_FILE_TYPE AS ucm_file_type , contents_master.UCM_LIMIT_AGE AS ucm_limit_age , contents_master.UCM_UCS_CODE AS ucm_ucs_code , contents_master.UCM_SERIES_NO AS ucm_series_no , contents_master.UCM_SERIES_NO AS ucm_series_no , (SELECT COUNT(UCM_CODE) FROM TBL_CONTENTS_MASTER WHERE ucm_ucs_code != '' AND UCM_UCS_CODE = contents_master.UCM_UCS_CODE AND UCM_STATUS = 'S' AND UCM_SVRYN = 'Y' ) AS ucm_series_count FROM TBL_BOOK_REPORT book_report LEFT OUTER JOIN TBL_CONTENTS_MASTER contents_master ON book_report.UBR_UCM_CODE = contents_master.UCM_CODE
JOIN TBL_RETURN_CONTENTS return_contents ON contents_master.UCM_CODE = return_contents.URC_UCM_CODE AND return_contents.URC_UCM_CODE = book_report.UBR_UCM_CODE
LEFT OUTER JOIN ( SELECT UCE_UCM_CODE FROM TBL_CONTENTS_EXCLUDE WHERE UCE_UIS_CODE = #{uis_code} ) V ON V.UCE_UCM_CODE = contents_master.UCM_CODE WHERE 1 = 1 AND contents_master.UCM_STATUS = 'S' AND contents_master.UCM_SVRYN = 'Y' AND V.uce_ucm_code is null
AND return_contents.URC_UIS_CODE = #{uis_code}
AND contents_master.UCM_COPY_BOOK_FLAG = 'N'
AND (book_report.UBR_IS_OPEN = 'Y' OR (book_report.UBR_IS_OPEN ='N' AND book_report.UBR_UIS_CODE = #{uis_code}))
AND contents_master.UCM_UCP_CODE = #{uis_ucp_code}
AND contents_master.UCM_UCP_CODE NOT IN ('UCP0000000425','UCP0000000013')
AND ( REPLACE(book_report.UBR_TITLE,' ','') COLLATE utf8_general_ci LIKE CONCAT('%', #{searchName}, '%') OR REPLACE(contents_master.UCM_TITLE,' ','') COLLATE utf8_general_ci LIKE CONCAT('%', #{searchName}, '%') OR REPLACE(contents_master.UCM_WRITER,' ','') COLLATE utf8_general_ci LIKE CONCAT('%', #{searchName}, '%') OR REPLACE(contents_master.UCM_PUBLISHER,' ','') COLLATE utf8_general_ci LIKE CONCAT('%', #{searchName}, '%') ) GROUP BY book_report.UBR_UCM_CODE LIMIT #{pagenum}, #{pageSize}

mapper.insert:
INSERT INTO TBL_MEMBER_LIBRARY_BOOK_HISTORY ( UMEH_CODE, UMEH_UML_CODE, UMEH_UM_CODE, UMEH_UCM_CODE, UMEH_UDR_CODE, UMEH_SEQ, UMEH_LAST_READ_PERCENT, UMEH_LAST_READ_IDX, UMEH_LAST_READ_POSITION, UMEH_WEB_LAST_READ_PERCENT, UMEH_WEB_LAST_READ_IDX, UMEH_WEB_LAST_READ_POSITION, UMEH_LAST_READ_DATE, UMEH_FINISHREAD_COUNT, UMEH_FINISHREAD_DATE, UMEH_READ_STATUS, UMEH_ISLOCK, UMEH_PASSWORD, UMEH_STATUS, UMEH_ISDOWNLOAD, UMEH_DOWNLOAD_DATE, UMEH_RATE, UMEH_RATE_MEMO, UMEH_MOD_DATE, UMEH_INPUT_DATE, UMEH_REGDATE, UMEH_UMD_UID, UMEH_HISTORYDATE ) (SELECT *, NOW() FROM TBL_MEMBER_LIBRARY_BOOK WHERE UME_UM_CODE = #{uml_um_code} AND UME_CODE IN
#{item}
)

mapper.select:
SELECT UEM_CODE AS uem_code , UEM_TITLE AS uem_title , UEM_THUMBNAIL_IMAGE AS uem_thumbnail_image , UEM_URL AS uem_url , DATE_FORMAT(UEM_DISPLAY_STARTDATE, '%Y-%m-%d') AS uem_display_startdate , DATE_FORMAT(UEM_DISPLAY_ENDDATE, '%Y-%m-%d') AS uem_display_enddate , UEM_UIS_USERID AS uem_uis_userid , UEM_USEYN AS uem_useyn , UEM_TYPE AS uem_type , UEM_DISPLAY_NUMBER AS uem_display_number , DATE_FORMAT(UEM_REGDATE, '%Y-%m-%d') AS uem_regdate , TIMESTAMPDIFF(DAY,DATE_FORMAT(NOW(), '%Y-%m-%d'),DATE_FORMAT(UEM_DISPLAY_ENDDATE, '%Y-%m-%d')) AS date_diff FROM TBL_EVENT_MASTER event_master
LEFT OUTER JOIN ( SELECT UEE_UEM_CODE FROM TBL_EVENT_EXCLUDE WHERE UEE_UIS_CODE = #{uis_code} AND UEE_DEL_YN = 'N' ) V ON V.UEE_UEM_CODE = event_master.UEM_CODE WHERE V.UEE_UEM_CODE is null AND UEM_DISPLAY_STARTDATE <= NOW() AND UEM_USEYN = 'Y' AND ( UEM_UIS_CODE IS NULL OR UEM_UIS_CODE = #{uis_code} ) AND STR_TO_DATE(UEM_DISPLAY_ENDDATE, '%Y-%m-%d %H:%i:%s') >= NOW() ORDER BY UEM_DISPLAY_NUMBER ASC
LIMIT #{pagenum}, #{pageSize}

SELECT UEM_CODE AS uem_code , UEM_TITLE AS uem_title , UEM_THUMBNAIL_IMAGE AS uem_thumbnail_image , UEM_URL AS uem_url , DATE_FORMAT(UEM_DISPLAY_STARTDATE, '%Y-%m-%d') AS uem_display_startdate , DATE_FORMAT(UEM_DISPLAY_ENDDATE, '%Y-%m-%d') AS uem_display_enddate , UEM_UIS_USERID AS uem_uis_userid , UEM_USEYN AS uem_useyn , UEM_TYPE AS uem_type , UEM_DISPLAY_NUMBER AS uem_display_number , DATE_FORMAT(UEM_REGDATE, '%Y-%m-%d') AS uem_regdate , TIMESTAMPDIFF(DAY,DATE_FORMAT(NOW(), '%Y-%m-%d'),DATE_FORMAT(UEM_DISPLAY_ENDDATE, '%Y-%m-%d')) AS date_diff FROM TBL_EVENT_MASTER event_master
LEFT OUTER JOIN ( SELECT UEE_UEM_CODE FROM TBL_EVENT_EXCLUDE WHERE UEE_UIS_CODE = #{uis_code} AND UEE_DEL_YN = 'N' ) V ON V.UEE_UEM_CODE = event_master.UEM_CODE WHERE V.UEE_UEM_CODE is null AND UEM_DISPLAY_STARTDATE <= NOW() AND ( UEM_UIS_CODE IS NULL OR UEM_UIS_CODE = #{uis_code} ) AND STR_TO_DATE(UEM_DISPLAY_ENDDATE, '%Y-%m-%d %H:%i:%s') < NOW() AND UEM_USEYN = 'Y' ORDER BY UEM_DISPLAY_NUMBER ASC
LIMIT #{pagenum}, #{pageSize}

SELECT UEM_CODE AS uem_code , UEM_UIS_CODE AS uem_uis_code , UEM_TITLE AS uem_title , UEM_WEB_DETAIL_IMAGE AS uem_web_detail_image , UEM_MOBILE_DETAIL_IMAGE AS uem_mobile_detail_image , UEM_A_WEB_DETAIL_IMAGE AS uem_a_web_detail_image , UEM_A_MOBILE_DETAIL_IMAGE AS uem_a_mobile_detail_image , UEM_WEB_NOTICE_IMAGE AS uem_web_notice_image , UEM_MOBILE_NOTICE_IMAGE AS uem_mobile_notice_image , DATE_FORMAT(UEM_DISPLAY_STARTDATE, '%Y-%m-%d') AS uem_display_startdate , DATE_FORMAT(UEM_DISPLAY_ENDDATE, '%Y-%m-%d') AS uem_display_enddate , UEM_USEYN AS uem_useyn , UEM_TYPE AS uem_type , UEM_URL AS uem_url , DATE_FORMAT(UEM_REGDATE, '%Y-%m-%d') AS uem_regdate , TIMESTAMPDIFF(DAY,DATE_FORMAT(NOW(), '%Y-%m-%d'),DATE_FORMAT(UEM_DISPLAY_ENDDATE, '%Y-%m-%d')) AS date_diff , (SELECT UM_USERID FROM TBL_B2B_MEMBER_MASTER WHERE UM_CODE = #{um_code}) AS um_userid , (SELECT UIS_COMPANY_FLAG FROM TBL_INSTITUTION_MASTER WHERE UIS_CODE = #{uis_code}) AS uis_company_flag , UEM_WEB_BUTTON AS uem_web_button , UEM_MOBILE_BUTTON AS uem_mobile_button , UEM_BOOK_YN AS uem_book_yn , UEM_BOOK_LINK AS uem_book_link FROM TBL_EVENT_MASTER WHERE UEM_CODE = #{uem_code}
AND UEM_UIS_CODE = #{uis_code}
AND UEM_DISPLAY_STARTDATE <= NOW()

mapper.delete:
DELETE FROM TBL_EVENT_COMMENT
WHERE
	UEMC_CODE = #{uemc_code}
AND
	UEMC_UIS_CODE = #{uis_code}
AND
	UEMC_UM_CODE = #{um_code}

