	UEMC_COMMENT = #{uemc_comment}
WHERE
	UEMC_CODE = #{uemc_code}
AND
	UEMC_UIS_CODE = #{uis_code}
AND
	UEMC_UM_CODE = #{um_code}

mapper.select:
SELECT contents_master.UCM_CODE AS ucm_code , contents_master.UCM_EBOOK_ISBN AS ucm_ebook_isbn , contents_master.UCM_FILE_TYPE AS ucm_file_type , contents_master.UCM_TITLE AS ucm_title , contents_master.UCM_SUB_TITLE AS ucm_sub_title , contents_master.UCM_UCP_CODE AS ucm_ucp_code , contents_master.UCM_WRITER AS ucm_writer , contents_master.UCM_THUMB_URL AS ucm_cover_url , contents_master.UCM_PUBLISHER AS ucm_publisher , contents_master.UCM_LIMIT_AGE AS ucm_limit_age , IFNULL((select ume_finishread_count from TBL_MEMBER_LIBRARY_BOOK tmlb where tmlb.ume_ucm_code = event_content.uec_ucm_code and tmlb.ume_um_code = #{um_code} limit 1),0) as ume_finishread_count , IFNULL((select ubr_code from TBL_BOOK_REPORT tbr where tbr.ubr_ucm_code = event_content.uec_ucm_code and tbr.ubr_um_code = #{um_code} limit 1),'') as ubr_code FROM TBL_EVENT_CONTENT event_content INNER JOIN TBL_CONTENTS_MASTER contents_master ON event_content.UEC_UCM_CODE = contents_master.UCM_CODE
JOIN TBL_RETURN_CONTENTS return_contents ON contents_master.UCM_CODE = return_contents.URC_UCM_CODE
LEFT OUTER JOIN ( SELECT UCE_UCM_CODE FROM TBL_CONTENTS_EXCLUDE WHERE UCE_UIS_CODE = #{uis_code} ) V ON V.UCE_UCM_CODE = contents_master.UCM_CODE WHERE V.uce_ucm_code is null AND event_content.UEC_UEM_CODE = #{uem_code} AND contents_master.UCM_STATUS = 'S' AND contents_master.UCM_SVRYN = 'Y'
AND return_contents.URC_UIS_CODE = #{uis_code}
ORDER BY event_content.uec_no asc LIMIT #{pagenum}, #{pageSize}

SELECT COUNT(*)
FROM TBL_CONTENTS_EXCLUDE
WHERE UCE_UIS_CODE = #{uisCode}
  AND UCE_UCM_CODE = #{ucmCode}

SELECT DISTINCT category.UCT_TYPE FROM TBL_CATEGORY_MASTER category WHERE category.UCT_DEPTH = 0 AND category.UCT_TYPE IN ('E','A') AND EXISTS ( SELECT 1 FROM TBL_CONTENTS_MASTER content
INNER JOIN TBL_RETURN_CONTENTS rc ON rc.URC_UCM_CODE = content.UCM_CODE AND rc.URC_UIS_CODE = #{uis_code}
WHERE content.UCM_MAIN_CODE = category.UCT_MAIN_CODE AND content.UCM_STATUS = 'S' AND content.UCM_SVRYN = 'Y'
AND content.UCM_UCP_CODE = #{uis_ucp_code}
AND content.UCM_COPY_BOOK_FLAG = 'N'
AND NOT EXISTS ( SELECT 1 FROM TBL_CONTENTS_EXCLUDE e WHERE e.UCE_UCM_CODE = content.UCM_CODE AND e.UCE_UIS_CODE = #{uis_code} ) );
